MERGE INTO CONSULTAS FIN USING (SELECT '800679InformeF10ReservasConsolidada' INFORME ,TO_CLOB(q'[SELECT RUBRO                    CODIGO_RUBRO_PRESUPUESTAL,
       MAX(NOMBRE)                                  NOMBRE_RUBRO_PRESUPUESTAL,
       SUM(RESERVA_CONSTITUIDA)                         VALOR_RESERVA_CONSTITUIDA,          
       ACTA_CANCELACION                                       No_ACTA_DE_LA_MODIFICACION,
       SUM(PAGO)                             VALOR_PAGADO   

FROM SIA_EJECUCION_RESERVA_PRESUPUESTAL
WHERE        ANO=s$ano$s
      AND MES_INICIAL>=s$mesInicial$s
      AND MES_FINAL <=s$mesFinal$s
 GROUP BY  RUBRO,  ACTA_CANCELACION]') CONSULTA, 99 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);